import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.MalformedURLException;
import java.net.URL;

public class HttpClient {
    public static String sendGetRequest(String urlStr, boolean isHttps) throws IOException {
        URL url = new URL(urlStr);
        HttpURLConnection con = (HttpURLConnection) url.openConnection();

        if (isHttps) {
            con.setSSLSocketFactory(HttpsURLConnectionUtils.getDefaultSSLSocketFactory());
        }

        con.setRequestMethod("GET");
        con.connect();
        int responseCode = con.getResponseCode();

        if (responseCode == 200) {
            InputStream is = con.getInputStream();
            BufferedReader reader = new BufferedReader(new InputStreamReader(is));
            StringBuilder builder = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                builder.append(line);
            }
            return builder.toString();
        } else {
            throw new IOException("Failed : HTTP error code : " + responseCode);
        }
    }
}